    {
      "term": "Ring Final Circuit",
      "simpleDefinition": "A circuit where the conductors form a continuous loop, starting and ending at the same protective device in the distribution board.",
      "anchor": "Think of it like a circular race track where electricity can travel in two directions to reach the same socket.",
      "misconception": "Thinking a ring circuit is just any circuit with multiple sockets; it specifically requires the cable to return to the board."
    },
    {
      "term": "Radial Circuit",
      "simpleDefinition": "A circuit that runs from the distribution board to the outlets and ends at the final point without returning.",
      "anchor": "Like a dead-end street; the power goes out to the points of use but does not loop back to the start.",
      "misconception": "Believing radials are only for lighting; they are also used for high-power appliances like cookers and showers."
    },
    {
      "term": "Control Circuit",
      "simpleDefinition": "A circuit used to signal, monitor, or switch the operation of another circuit or piece of equipment.",
      "anchor": "Like a light switch or a thermostat; it doesn't do the heavy work, it just tells the main equipment when to start.",
      "misconception": "Assuming control circuits always carry high voltage; they often operate at lower, safer voltages."
    },
    {
      "term": "SWA (Steel Wire Armoured)",
      "simpleDefinition": "A cable with a layer of steel wire for mechanical protection, suitable for burial or industrial use.",
      "anchor": "The 'armour' makes it tough enough to withstand being hit by a spade or crushed in a factory.",
      "misconception": "Thinking the steel wires are the main power conductors; they are for physical protection and earthing only."
    },
    {
      "term": "MICC (Mineral Insulated Copper Clad)",
      "simpleDefinition": "A fire-resistant cable using compressed powder insulation, designed to maintain circuit integrity during a fire.",
      "anchor": "Often called 'pyro'; it is used for emergency systems because it can survive extreme heat.",
      "misconception": "Thinking it is standard cable; it requires specialized tools and seals to prevent moisture from entering the powder."
    },
    {
      "term": "Trunking",
      "simpleDefinition": "A square or rectangular enclosure with a removable lid used to protect and route multiple cables.",
      "anchor": "A 'highway' for cables, usually seen on walls in offices or commercial buildings for easy access.",
      "misconception": "Confusing trunking with conduit; trunking has a removable lid, while conduit is a solid tube."
    },
    {
      "term": "Hazardous Environment",
      "simpleDefinition": "An area where there is a risk of explosion or fire due to the presence of flammable gases, vapors, or dust.",
      "anchor": "Places like petrol stations or flour mills where a single spark could cause an explosion.",
      "misconception": "Thinking 'hazardous' just means a building is old or messy; it specifically refers to explosive atmospheres."
    }
  ],
  "anchorPhrases": [
    "A ring final circuit forms a complete loop back to the board.",
    "Radial circuits end at the last point of use.",
    "SWA provides mechanical protection for harsh environments.",
    "MICC is used for fire-resistant emergency circuits.",
    "Trunking uses a removable lid for cable access."
  ],
  "misconceptionTargets": [
    "A ring circuit must return to its origin to be a ring.",
    "Radial circuits are not limited to lighting; they serve heavy loads too.",
    "Hazardous environments require specialized equipment to prevent explosions.",
    "The steel in SWA is for protection, not for carrying the main load current."
  ]
}

